// Parse the LLM response and extract scores
const response = $input.first().json;
const leads = $('Format Batch Prompt').first().json.leads;

let scores = [];
try {
  // Extract JSON from response
  const content = response.choices[0].message.content;
  // Try to parse as JSON directly
  scores = JSON.parse(content);
} catch (e) {
  // If parsing fails, try to extract JSON from text
  const match = response.choices[0].message.content.match(/\[.*\]/s);
  if (match) {
    scores = JSON.parse(match[0]);
  }
}

// Map scores back to lead IDs
const results = scores.map(s => {
  const lead = leads.find(l => l.index === s.index);
  return {
    json: {
      id: lead?.id,
      score: s.score,
      reason: s.reason,
      status: s.score >= 7 ? 'READY' : s.score >= 5 ? 'MEDIUM' : 'LOW_PRIORITY'
    }
  };
});

return results;
